    __m512d y0_re,y0_im,y1_re,y1_im,y2_re,y2_im,y3_re,y3_im;

    /* Hoisted internal W32 broadcasts */
    const __m512d tw_W32_1_re = _mm512_set1_pd(W32_1_re);
