        s4_re = x4_re; s4_im = x4_im;
        s5_re = x5_re; s5_im = x5_im;
        s6_re = x6_re; s6_im = x6_im;
        s7_re = x7_re; s7_im = x7_im;

        /* PASS 2 (fused, n2=3 from s-regs) */

        /* column k1=0: y0..y2 from spill, y3 from s0 */
        y0_re = _mm512_load_pd(&spill_re[0*8]);
        y0_im = _mm512_load_pd(&spill_im[0*8]);
        y1_re = _mm512_load_pd(&spill_re[8*8]);
        y1_im = _mm512_load_pd(&spill_im[8*8]);
        y2_re = _mm512_load_pd(&spill_re[16*8]);
        y2_im = _mm512_load_pd(&spill_im[16*8]);
