          t2r=_mm512_add_pd(y1_re,y3_re); t2i=_mm512_add_pd(y1_im,y3_im);
          t3r=_mm512_sub_pd(y1_re,y3_re); t3i=_mm512_sub_pd(y1_im,y3_im);
          y0_re=_mm512_add_pd(t0r,t2r); y0_im=_mm512_add_pd(t0i,t2i);
