        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_im);
          _mm512_store_pd(&out[2*(24*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(24*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }

        /* column k1=1: y0..y2 from spill, y3 from s1 */
        y0_re = _mm512_load_pd(&spill_re[1*8]);
