        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y0_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y0_im);
          _mm512_store_pd(&out[2*(6*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(6*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y1_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y1_im);
          _mm512_store_pd(&out[2*(14*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(14*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y2_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y2_im);
          _mm512_store_pd(&out[2*(22*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(22*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_im);
          _mm512_store_pd(&out[2*(30*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(30*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }

        /* A_column k1=7: y0..y2 from spill, y3 from s7 */
        y0_re = _mm512_load_pd(&spill_re[7*8]);
        y0_im = _mm512_load_pd(&spill_im[7*8]);
        y1_re = _mm512_load_pd(&spill_re[15*8]);
        y1_im = _mm512_load_pd(&spill_im[15*8]);
        y2_re = _mm512_load_pd(&spill_re[23*8]);
        y2_im = _mm512_load_pd(&spill_im[23*8]);
        y3_re = s7_re; y3_im = s7_im;

        { __m512d tr=y1_re;
          y1_re=_mm512_fmsub_pd(y1_re,tw_W32_7_re,_mm512_mul_pd(y1_im,tw_W32_7_im));
          y1_im=_mm512_fmadd_pd(tr,tw_W32_7_im,_mm512_mul_pd(y1_im,tw_W32_7_re)); }
        { __m512d tr=y2_re;
          y2_re=_mm512_fmsub_pd(y2_re,tw_W32_14_re,_mm512_mul_pd(y2_im,tw_W32_14_im));
          y2_im=_mm512_fmadd_pd(tr,tw_W32_14_im,_mm512_mul_pd(y2_im,tw_W32_14_re)); }
        { __m512d tr=y3_re;
          y3_re=_mm512_fmsub_pd(y3_re,tw_W32_21_re,_mm512_mul_pd(y3_im,tw_W32_21_im));
          y3_im=_mm512_fmadd_pd(tr,tw_W32_21_im,_mm512_mul_pd(y3_im,tw_W32_21_re)); }

        /* A_radix-4 k1=7 [fwd] */
        { __m512d t0r,t0i,t1r,t1i,t2r,t2i,t3r,t3i;
          t0r=_mm512_add_pd(y0_re,y2_re); t0i=_mm512_add_pd(y0_im,y2_im);
          t1r=_mm512_sub_pd(y0_re,y2_re); t1i=_mm512_sub_pd(y0_im,y2_im);
          t2r=_mm512_add_pd(y1_re,y3_re); t2i=_mm512_add_pd(y1_im,y3_im);
          t3r=_mm512_sub_pd(y1_re,y3_re); t3i=_mm512_sub_pd(y1_im,y3_im);
          y0_re=_mm512_add_pd(t0r,t2r); y0_im=_mm512_add_pd(t0i,t2i);
          y2_re=_mm512_sub_pd(t0r,t2r); y2_im=_mm512_sub_pd(t0i,t2i);
          y1_re=_mm512_add_pd(t1r,t3i); y1_im=_mm512_sub_pd(t1i,t3r);
          y3_re=_mm512_sub_pd(t1r,t3i); y3_im=_mm512_add_pd(t1i,t3r);
        }

        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y0_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y0_im);
          _mm512_store_pd(&out[2*(7*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(7*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y1_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y1_im);
          _mm512_store_pd(&out[2*(15*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(15*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y2_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y2_im);
          _mm512_store_pd(&out[2*(23*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(23*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }
        { __m512d _rp = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_re);
          __m512d _ip = _mm512_permutexvar_pd(_mm512_set_epi64(7,3,6,2,5,1,4,0), y3_im);
          _mm512_store_pd(&out[2*(31*K+k)], _mm512_unpacklo_pd(_rp,_ip));
          _mm512_store_pd(&out[2*(31*K+k+4)], _mm512_unpackhi_pd(_rp,_ip)); }

        /* Pipeline B [fwd] */
        /* B_Load 5 base twiddle pairs */
        const __m512d B_b1_re = _mm512_load_pd(&base_tw_re[0*K+k+8]);
        const __m512d B_b1_im = _mm512_load_pd(&base_tw_im[0*K+k+8]);
        const __m512d B_b2_re = _mm512_load_pd(&base_tw_re[1*K+k+8]);
        const __m512d B_b2_im = _mm512_load_pd(&base_tw_im[1*K+k+8]);
        const __m512d B_b4_re = _mm512_load_pd(&base_tw_re[2*K+k+8]);
        const __m512d B_b4_im = _mm512_load_pd(&base_tw_im[2*K+k+8]);
        const __m512d B_b8_re = _mm512_load_pd(&base_tw_re[3*K+k+8]);
        const __m512d B_b8_im = _mm512_load_pd(&base_tw_im[3*K+k+8]);
        const __m512d B_b16_re = _mm512_load_pd(&base_tw_re[4*K+k+8]);
        const __m512d B_b16_im = _mm512_load_pd(&base_tw_im[4*K+k+8]);

        /* B_Derive b3 = b1*b2 */
        __m512d B_b3_re, B_b3_im;
        B_b3_re = _mm512_fmsub_pd(B_b1_re,B_b2_re,_mm512_mul_pd(B_b1_im,B_b2_im));
        B_b3_im = _mm512_fmadd_pd(B_b1_re,B_b2_im,_mm512_mul_pd(B_b1_im,B_b2_re));

        __m512d B_r3_re,B_r3_im, B_r5_re,B_r5_im, B_r6_re,B_r6_im, B_r7_re,B_r7_im;
        __m512d B_b12_re, B_b12_im;

        /* B_sub-FFT n2=0 */
        { __m512d _lo = _mm512_load_pd(&in[2*(0*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(0*K+k+8+4)]);
          x0_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x0_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        { __m512d _lo = _mm512_load_pd(&in[2*(4*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(4*K+k+8+4)]);
          x1_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x1_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        { __m512d tr=x1_re;
          x1_re=_mm512_fmsub_pd(x1_re,B_b4_re,_mm512_mul_pd(x1_im,B_b4_im));
          x1_im=_mm512_fmadd_pd(tr,B_b4_im,_mm512_mul_pd(x1_im,B_b4_re)); }
        { __m512d _lo = _mm512_load_pd(&in[2*(8*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(8*K+k+8+4)]);
          x2_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x2_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        { __m512d tr=x2_re;
          x2_re=_mm512_fmsub_pd(x2_re,B_b8_re,_mm512_mul_pd(x2_im,B_b8_im));
          x2_im=_mm512_fmadd_pd(tr,B_b8_im,_mm512_mul_pd(x2_im,B_b8_re)); }
        { __m512d _lo = _mm512_load_pd(&in[2*(12*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(12*K+k+8+4)]);
          x3_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x3_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        B_r3_re = _mm512_fmsub_pd(B_b4_re,B_b8_re,_mm512_mul_pd(B_b4_im,B_b8_im));
        B_r3_im = _mm512_fmadd_pd(B_b4_re,B_b8_im,_mm512_mul_pd(B_b4_im,B_b8_re));
        B_b12_re = B_r3_re; B_b12_im = B_r3_im;
        { __m512d tr=x3_re;
          x3_re=_mm512_fmsub_pd(x3_re,B_r3_re,_mm512_mul_pd(x3_im,B_r3_im));
          x3_im=_mm512_fmadd_pd(tr,B_r3_im,_mm512_mul_pd(x3_im,B_r3_re)); }
        { __m512d _lo = _mm512_load_pd(&in[2*(16*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(16*K+k+8+4)]);
          x4_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x4_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        { __m512d tr=x4_re;
          x4_re=_mm512_fmsub_pd(x4_re,B_b16_re,_mm512_mul_pd(x4_im,B_b16_im));
          x4_im=_mm512_fmadd_pd(tr,B_b16_im,_mm512_mul_pd(x4_im,B_b16_re)); }
        { __m512d _lo = _mm512_load_pd(&in[2*(20*K+k+8)]);
          __m512d _hi = _mm512_load_pd(&in[2*(20*K+k+8+4)]);
          x5_re = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpacklo_pd(_lo,_hi));
          x5_im = _mm512_permutexvar_pd(_mm512_set_epi64(7,5,3,1,6,4,2,0), _mm512_unpackhi_pd(_lo,_hi)); }
        B_r5_re = _mm512_fmsub_pd(B_b4_re,B_b16_re,_mm512_mul_pd(B_b4_im,B_b16_im));
        B_r5_im = _mm512_fmadd_pd(B_b4_re,B_b16_im,_mm512_mul_pd(B_b4_im,B_b16_re));
